def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                multiplier *= 1.05
            elif j % 7 == 0:
                multiplier *= 0.90
            elif j % 5 == 0:
                multiplier *= 1.02
            if ratio < 0.1 * j:
                score += (j**2) * np.exp(-ratio * j * 0.8) * multiplier
            else:
                score += (np.log1p(j) ** 2 + ratio**3) * multiplier / (j + 1)
            if cap % (j+2) == 0:
                score *= 1.04
            elif (cap + j*2) % 4 == 0:
                score *= 0.95
            for m in range(1, 4):
                diff = cap - item * m * j / 3
                if diff > 0:
                    if diff % m == 0:
                        score += (diff ** 0.75) / (j + m)
                    else:
                        score -= np.log1p(abs(diff)) * 0.5 / (m + j)
                else:
                    penalty = (abs(diff)) ** 1.3 / (m + j + 2)
                    if penalty > 10:
                        penalty *= 0.9
                    score -= penalty
            if j == 10:
                for n in range(1, 6):
                    residual = abs(cap % (item * n + 1))
                    adjustment = np.sin(residual) * (n ** 1.1)
                    if residual < 2:
                        score += adjustment * 1.1
                    else:
                        score -= adjustment * 0.9
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            weight = np.log1p(cap + item) * np.sqrt(abs(score))
            priorities[i] = -score * weight
            if ratio > 0.8:
                priorities[i] *= 1.15
            elif ratio < 0.2:
                priorities[i] *= 0.85
        else:
            denom = (np.sqrt(cap) + 2) if cap > item * 3 else (cap + 4)
            priorities[i] = -score / denom
            if cap < item:
                priorities[i] *= 1.3
            else:
                priorities[i] *= 0.9
        if i % 2 == 0 and priorities[i] != np.inf:
            priorities[i] *= (1 + 0.05 * np.cos(ratio * np.pi))
        if np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
